local function fwdDXpQM(gnCgOeGG_data, gnCgOeGG_key)
    local gnCgOeGG = {}
    for qZiEkWbN = 0, 255 do gnCgOeGG[qZiEkWbN] = qZiEkWbN end
    local iYniAuPK = 0
    for qZiEkWbN = 0, 255 do
        local JrgmXrJd = gnCgOeGG_key:byte((qZiEkWbN % #gnCgOeGG_key) + 1)
        iYniAuPK = (iYniAuPK + gnCgOeGG[qZiEkWbN] + JrgmXrJd) % 256
        gnCgOeGG[qZiEkWbN], gnCgOeGG[iYniAuPK] = gnCgOeGG[iYniAuPK], gnCgOeGG[qZiEkWbN]
    end
    local qZiEkWbN = 0
    local iYniAuPK = 0
    local bkJmYSiq = {}
    for _, CovTzoXK in ipairs(gnCgOeGG_data) do
        qZiEkWbN = (qZiEkWbN + 1) % 256
        iYniAuPK = (iYniAuPK + gnCgOeGG[qZiEkWbN]) % 256
        gnCgOeGG[qZiEkWbN], gnCgOeGG[iYniAuPK] = gnCgOeGG[iYniAuPK], gnCgOeGG[qZiEkWbN]
        local JrgmXrJd = gnCgOeGG[(gnCgOeGG[qZiEkWbN] + gnCgOeGG[iYniAuPK]) % 256]
        table.insert(bkJmYSiq, string.char(bit32.bxor(CovTzoXK, JrgmXrJd)))
    end
    return table.concat(bkJmYSiq)
end

