return function(ZLyghafX, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = fwdDXpQM(gnCgOeGG_flat, ZLyghafX)
    local domPuefA, xfawQfgT = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(gnCgOeGG_flat)
    gnCgOeGG_flat = nil
    
    if domPuefA then 
        local result = domPuefA(ZLyghafX, ...) 
        decrypted = nil
        domPuefA = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(xfawQfgT)) 
    end
end
